#[derive(Copy, Clone, Eq, PartialEq)]
struct Node {
    position: (usize, usize),
    cost: i32,
    estimated_cost: i32,
}

impl Ord for Node {
    fn cmp(&self, other: &Self) -> Ordering {
        other.estimated_cost.cmp(&self.estimated_cost)
            .then_with(|| other.cost.cmp(&self.cost))
    }
}

impl PartialOrd for Node {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

fn manhattan_distance(p1: (usize, usize), p2: (usize, usize)) -> i32 {
    (p1.0 as i32 - p2.0 as i32).abs() + (p1.1 as i32 - p2.1 as i32).abs()
}

pub fn find_path_in_maze(maze: Vec<Vec<i32>>, start: (usize, usize), end: (usize, usize)) -> Option<Vec<(usize, usize)>> {
    let directions = [(0, 1), (1, 0), (0, -1), (-1, 0)];
    let mut open_set = BinaryHeap::new();
    let mut came_from: HashMap<(usize, usize), (usize, usize)> = HashMap::new();
    let mut g_score: HashMap<(usize, usize), i32> = HashMap::new();

    g_score.insert(start, 0);
    open_set.push(Node { position: start, cost: 0, estimated_cost: manhattan_distance(start, end) });

    while let Some(Node { position, cost, .. }) = open_set.pop() {
        if position == end {
            let mut path = vec![end];
            let mut current = end;
            while let Some(&prev) = came_from.get(&current) {
                path.push(prev);
                current = prev;
            }
            path.reverse();
            return Some(path);
        }

        for &dir in &directions {
            let (x, y) = (position.0 as isize + dir.0, position.1 as isize + dir.1);
            if x >= 0 && y >= 0 {
                let next_pos = (x as usize, y as usize);
                if next_pos.0 < maze.len() && next_pos.1 < maze[0].len() && maze[next_pos.0][next_pos.1] == 0 {
                    let tentative_g_score = cost + 1;
                    if tentative_g_score < *g_score.get(&next_pos).unwrap_or(&i32::MAX) {
                        came_from.insert(next_pos, position);
                        g_score.insert(next_pos, tentative_g_score);
                        open_set.push(Node { position: next_pos, cost: tentative_g_score, estimated_cost: tentative_g_score + manhattan_distance(next_pos, end) });
                    }
                }
            }
        }
    }
    None
}
