function findCentroids(dataPoints, k) {
    function distanceSquared(point1, point2) {
        return (point1.x - point2.x) ** 2 + (point1.y - point2.y) ** 2;
    }

    function average(points) {
        const total = points.reduce((sum, point) => ({ x: sum.x + point.x, y: sum.y + point.y }), { x: 0, y: 0 });
        return { x: total.x / points.length, y: total.y / points.length };
    }

    // Initialize centroids randomly
    let centroids = dataPoints.slice(0, k);

    let hasChanged = true;
    while (hasChanged) {
        const clusters = Array.from({ length: k }, () => []);

        // Assign points to the nearest centroid
        dataPoints.forEach(point => {
            let closestIndex = 0;
            let closestDistance = distanceSquared(point, centroids[0]);

            for (let i = 1; i < k; i++) {
                const distance = distanceSquared(point, centroids[i]);
                if (distance < closestDistance) {
                    closestDistance = distance;
                    closestIndex = i;
                }
            }
            clusters[closestIndex].push(point);
        });

        hasChanged = false;

        // Update centroids to be the center of their cluster
        for (let i = 0; i < k; i++) {
            if (clusters[i].length === 0) continue;
            const newCentroid = average(clusters[i]);
            if (newCentroid.x !== centroids[i].x || newCentroid.y !== centroids[i].y) {
                centroids[i] = newCentroid;
                hasChanged = true;
            }
        }
    }

    return centroids;
}
