fn find_all_scc(graph: &Vec<Vec<usize>>) -> Vec<Vec<usize>> {
    let mut index = 0;
    let mut stack = Vec::new();
    let mut indices = vec![-1; graph.len()];
    let mut lowlink = vec![0; graph.len()];
    let mut on_stack = vec![false; graph.len()];
    let mut sccs = Vec::new();

    fn strongconnect(
        v: usize, 
        index: &mut i32, 
        stack: &mut Vec<usize>, 
        indices: &mut Vec<i32>, 
        lowlink: &mut Vec<i32>, 
        on_stack: &mut Vec<bool>, 
        sccs: &mut Vec<Vec<usize>>, 
        graph: &Vec<Vec<usize>>) 
    {
        indices[v] = *index;
        lowlink[v] = *index;
        *index += 1;
        stack.push(v);
        on_stack[v] = true;

        for &w in &graph[v] {
            if indices[w] == -1 {
                strongconnect(w, index, stack, indices, lowlink, on_stack, sccs, graph);
                lowlink[v] = lowlink[v].min(lowlink[w]);
            } else if on_stack[w] {
                lowlink[v] = lowlink[v].min(indices[w]);
            }
        }

        if lowlink[v] == indices[v] {
            let mut scc = Vec::new();
            loop {
                let w = stack.pop().unwrap();
                on_stack[w] = false;
                scc.push(w);
                if w == v { break; }
            }
            sccs.push(scc);
        }
    }

    for v in 0..graph.len() {
        if indices[v] == -1 {
            strongconnect(v, &mut index, &mut stack, &mut indices, &mut lowlink, &mut on_stack, &mut sccs, graph);
        }
    }

    sccs
}
