import java.util.Arrays;

public class LongestRepeatedSubstring {

    public static String findLongestRepeatedSubstring(String text) {
        if (text == null || text.length() == 0) {
            return "";
        }

        int n = text.length();
        int[] suffixArray = buildSuffixArray(text, n);
        int[] lcp = buildLCP(text, n, suffixArray);
        int maxLength = 0;
        int idx = 0;

        for (int i = 1; i < n; i++) {
            if (lcp[i] > maxLength) {
                maxLength = lcp[i];
                idx = i;
            }
        }

        return maxLength > 0 ? text.substring(suffixArray[idx], suffixArray[idx] + maxLength) : "";
    }

    private static int[] buildSuffixArray(String text, int n) {
        Suffix[] suffixes = new Suffix[n];

        for (int i = 0; i < n; i++) {
            suffixes[i] = new Suffix(i, text.substring(i));
        }

        Arrays.sort(suffixes, (s1, s2) -> s1.suffix.compareTo(s2.suffix));

        int[] suffixArray = new int[n];
        for (int i = 0; i < n; i++) {
            suffixArray[i] = suffixes[i].index;
        }

        return suffixArray;
    }

    private static int[] buildLCP(String text, int n, int[] suffixArray) {
        int[] rank = new int[n];
        int[] lcp = new int[n];

        for (int i = 0; i < n; i++) {
            rank[suffixArray[i]] = i;
        }

        int h = 0;
        for (int i = 0; i < n; i++) {
            if (rank[i] > 0) {
                int j = suffixArray[rank[i] - 1];
                while (i + h < n && j + h < n && text.charAt(i + h) == text.charAt(j + h)) {
                    h++;
                }
                lcp[rank[i]] = h;
                if (h > 0) {
                    h--;
                }
            }
        }

        return lcp;
    }

    private static class Suffix {
        int index;
        String suffix;

        Suffix(int index, String suffix) {
            this.index = index;
            this.suffix = suffix;
        }
    }

    public static void main(String[] args) {
        System.out.println(findLongestRepeatedSubstring("banana")); // Output: "ana"
    }
}
