    int least = idx;
    int left = 2 * idx + 1;
    int right = 2 * idx + 2;

    if (left < pq->size && pq->distances[pq->priority[left]] < pq->distances[pq->priority[least]])
        least = left;

    if (right < pq->size && pq->distances[pq->priority[right]] < pq->distances[pq->priority[least]])
        least = right;

    if (least != idx) {
        int leastVertex = pq->priority[least];
        int idxVertex = pq->priority[idx];

        pq->position[leastVertex] = idx;
        pq->position[idxVertex] = least;

        swap(&pq->priority[least], &pq->priority[idx]);

        heapify(pq, least);
    }
}

int isEmpty(PriorityQueue* pq) {
    return pq->size == 0;
}

int extractMin(PriorityQueue* pq) {
    if (isEmpty(pq))
        return -1;
    int root = pq->priority[0];
    int last = pq->priority[pq->size - 1];
    pq->priority[0] = last;

    pq->position[root] = pq->size - 1;
    pq->position[last] = 0;

    --pq->size;
    heapify(pq, 0);
    return root;
}

void decreaseKey(PriorityQueue* pq, int v, int dist) {
    int idx = pq->position[v];
    pq->distances[v] = dist;

    while (idx && pq->distances[pq->priority[idx]] < pq->distances[pq->priority[(idx - 1) / 2]]) {
        pq->position[pq->priority[idx]] = (idx - 1) / 2;
        pq->position[pq->priority[(idx - 1) / 2]] = idx;
        swap(&pq->priority[idx], &pq->priority[(idx - 1) / 2]);
        idx = (idx - 1) / 2;
    }
}

int isInPriorityQueue(PriorityQueue* pq, int v) {
    if (pq->position[v] < pq->size)
        return 1;
    return 0;
}

void addEdge(Graph* graph, int src, int dest, int weight) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->vertex = dest;
    newNode->weight = weight;
    newNode->next = graph->adjLists[src];
    graph->adjLists[src] = newNode;
}

int* shortest_path(Graph* graph, int source) {
    int V = graph->numVertices;
    int* dist = (int*)malloc(V * sizeof(int));

    PriorityQueue* pq = createPriorityQueue(V);

    for (int v = 0; v < V; ++v) {
        dist[v] = INT_MAX;
        pq->priority[v] = v;
        pq->position[v] = v;
    }

    pq->size = V;
    dist[source] = 0;
    decreaseKey(pq, source, dist[source]);

    while (!isEmpty(pq)) {
        int u = extractMin(pq);

        Node* crawl = graph->adjLists[u];
        while (crawl != NULL) {
            int v = crawl->vertex;
            if (isInPriorityQueue(pq, v) && dist[u] != INT_MAX && dist[u] + crawl->weight < dist[v]) {
                dist[v] = dist[u] + crawl->weight;
                decreaseKey(pq, v, dist[v]);
            }
            crawl = crawl->next;
        }
    }

    free(pq->distances);
    free(pq->position);
    free(pq->priority);
    free(pq);
    return dist;
}
