class SuffixTree {
    struct Node {
        std::vector<Node*> children;
        int start, *end, suffixIndex;
        Node(int start, int* end) : start(start), end(end), suffixIndex(-1) {
            children = std::vector<Node*>(256, nullptr);
        }
    };

    std::string text;
    Node* root;
    int length;
    int* leafEnd;
    std::vector<int> suffixArray;

    Node* newNode(int start, int* end) {
        Node* node = new Node(start, end);
        node->suffixIndex = -1;
        return node;
    }

    void buildSuffixTree() {
        int size = text.size();
        int* rootEnd = new int(-1);
        root = newNode(-1, rootEnd);
        length = 0;
        leafEnd = new int(-1);
        for (int i = 0; i < size; i++) {
            extendSuffixTree(i);
        }
        int labelHeight = 0;
        setSuffixIndexByDFS(root, labelHeight);
    }

    void extendSuffixTree(int pos) {
        static Node* lastNewNode = nullptr;
        static int remainingSuffixCount = 0;
        static int activeLength = 0, activeEdge = -1;
        static Node* activeNode = nullptr;
        if (activeNode == nullptr) activeNode = root;

        (*leafEnd) = pos;
        remainingSuffixCount++;
        lastNewNode = nullptr;

        while (remainingSuffixCount > 0) {
            if (activeLength == 0) activeEdge = pos;

            if (activeNode->children[text[activeEdge]] == nullptr) {
                activeNode->children[text[activeEdge]] = newNode(pos, leafEnd);

                if (lastNewNode != nullptr) {
                    lastNewNode->suffixIndex = activeNode->suffixIndex;
                    lastNewNode = nullptr;
                }
            } else {
                Node* next = activeNode->children[text[activeEdge]];
                int edgeLength = *(next->end) - next->start + 1;
                if (activeLength >= edgeLength) {
                    activeEdge += edgeLength;
                    activeLength -= edgeLength;
                    activeNode = next;
                    continue;
                }
                if (text[next->start + activeLength] == text[pos]) {
                    if (lastNewNode != nullptr && activeNode != root) {
                        lastNewNode->suffixIndex = activeNode->suffixIndex;
                        lastNewNode = nullptr;
                    }
                    activeLength++;
                    break;
                }
                int* splitEnd = new int(next->start + activeLength - 1);
                Node* split = newNode(next->start, splitEnd);
                activeNode->children[text[activeEdge]] = split;
                split->children[text[pos]] = newNode(pos, leafEnd);
                next->start += activeLength;
                split->children[text[next->start]] = next;
                if (lastNewNode != nullptr) {
                    lastNewNode->suffixIndex = split->suffixIndex;
                }
                lastNewNode = split;
            }
            remainingSuffixCount--;
            if (activeNode == root && activeLength > 0) {
                activeLength--;
                activeEdge = pos - remainingSuffixCount + 1;
            } else if (activeNode != root) {
                activeNode = activeNode->suffixIndex;
            }
        }
    }

    void setSuffixIndexByDFS(Node* n, int labelHeight) {
        if (n == nullptr) return;
        if (n->start != -1) n->suffixIndex = text.size() - labelHeight;
        bool leaf = true;
        for (int i = 0; i < 256; i++) {
            if (n->children[i] != nullptr) {
                leaf = false;
                setSuffixIndexByDFS(n->children[i], labelHeight + *(n->children[i]->end) - n->children[i]->start + 1);
            }
        }
        if (leaf) {
            suffixArray.push_back(n->suffixIndex);
        }
    }

public:
    SuffixTree(const std::string& input) : text(input) {
        buildSuffixTree();
    }

    std::string findLongestRepeatedSubstring() {
        int maxLength = 0;
        int start = -1;
        std::string LRS;
        std::vector<int> h(text.size(), 0);

        for (size_t i = 1; i < text.size(); i++) {
            h[i] = commonPrefixLength(suffixArray[i - 1], suffixArray[i]);
            if (h[i] > maxLength) {
                maxLength = h[i];
                start = suffixArray[i];
            }
        }
        if (maxLength > 0) LRS = text.substr(start, maxLength);
        return LRS;
    }

    int commonPrefixLength(int i, int j) {
        int k = 0;
        while (i + k < text.size() && j + k < text.size() && text[i + k] == text[j + k]) {
            k++;
        }
        return k;
    }
};

std::string longest_repeated_substring(const std::string& s) {
    if (s.empty()) return "";
    SuffixTree suffixTree(s);
    return suffixTree.findLongestRepeatedSubstring();
}
