import java.util.*;

class HuffmanNode {
    char data;
    int frequency;
    HuffmanNode left, right;
}

class HuffmanComparator implements Comparator<HuffmanNode> {
    public int compare(HuffmanNode x, HuffmanNode y) {
        return x.frequency - y.frequency;
    }
}

public class HuffmanCoding {
    private Map<Character, String> charPrefixMap = new HashMap<>();
    private HuffmanNode root;

    public String compressData(String input) {
        if (input == null || input.isEmpty()) {
            return "";
        }

        Map<Character, Integer> frequencyMap = buildFrequencyMap(input);
        root = buildHuffmanTree(frequencyMap);
        buildPrefixMap(root, "");

        StringBuilder compressedData = new StringBuilder();
        for (char c : input.toCharArray()) {
            compressedData.append(charPrefixMap.get(c));
        }

        return compressedData.toString();
    }

    private Map<Character, Integer> buildFrequencyMap(String input) {
        Map<Character, Integer> frequencyMap = new HashMap<>();
        for (char c : input.toCharArray()) {
            frequencyMap.put(c, frequencyMap.getOrDefault(c, 0) + 1);
        }
        return frequencyMap;
    }

    private HuffmanNode buildHuffmanTree(Map<Character, Integer> frequencyMap) {
        PriorityQueue<HuffmanNode> heap = new PriorityQueue<>(new HuffmanComparator());

        for (Map.Entry<Character, Integer> entry : frequencyMap.entrySet()) {
            HuffmanNode node = new HuffmanNode();
            node.data = entry.getKey();
            node.frequency = entry.getValue();
            node.left = null;
            node.right = null;
            heap.add(node);
        }

        while (heap.size() > 1) {
            HuffmanNode x = heap.poll();
            HuffmanNode y = heap.poll();
            HuffmanNode newNode = new HuffmanNode();
            newNode.data = '-';
            newNode.frequency = x.frequency + y.frequency;
            newNode.left = x;
            newNode.right = y;
            heap.add(newNode);
        }

        return heap.poll();
    }

    private void buildPrefixMap(HuffmanNode node, String prefix) {
        if (node == null) return;

        if (node.left == null && node.right == null) {
            charPrefixMap.put(node.data, prefix);
        }

        buildPrefixMap(node.left, prefix + "0");
        buildPrefixMap(node.right, prefix + "1");
    }

    public static void main(String[] args) {
        HuffmanCoding hc = new HuffmanCoding();
        String compressed = hc.compressData("example data");
        System.out.println("Compressed Data: " + compressed);
    }
}
