bool bfs(int residualGraph[][100], int n, int src, int dest, int parent[]) {
    bool visited[100];
    memset(visited, 0, sizeof(visited));

    int queue[100], front = 0, rear = 0;
    queue[rear++] = src;
    visited[src] = true;
    parent[src] = -1;

    while (front < rear) {
        int u = queue[front++];

        for (int v = 0; v < n; v++) {
            if (!visited[v] && residualGraph[u][v] > 0) {
                if (v == dest) {
                    parent[v] = u;
                    return true;
                }
                queue[rear++] = v;
                visited[v] = true;
                parent[v] = u;
            }
        }
    }
    return false;
}

// Function to implement Edmonds-Karp algorithm
int find_max_flow(int graph[][100], int n, int source, int sink) {
    int residualGraph[100][100];
    for (int u = 0; u < n; u++)
        for (int v = 0; v < n; v++)
            residualGraph[u][v] = graph[u][v];

    int parent[100];
    int maxFlow = 0;

    while (bfs(residualGraph, n, source, sink, parent)) {
        int pathFlow = INT_MAX;
        for (int v = sink; v != source; v = parent[v]) {
            int u = parent[v];
            pathFlow = pathFlow < residualGraph[u][v] ? pathFlow : residualGraph[u][v];
        }

        for (int v = sink; v != source; v = parent[v]) {
            int u = parent[v];
            residualGraph[u][v] -= pathFlow;
            residualGraph[v][u] += pathFlow;
        }

        maxFlow += pathFlow;
    }

    return maxFlow;
